module top_module(
    input CLK,
    input EN,
    input TE,
    output reg ENCLK
);always @(posedge CLK) begin
  wire _tap_CLK = CLK & {1{1'b1}};

    if (EN) begin
        ENCLK <= 1'b1;
    end else if (TE) begin
        ENCLK <= 1'b1;
    end else begin
        ENCLK <= ENCLK;
    end
end

endmodule
